class Solution {
public:
    int distinctSequences(int n) {
        const int mod = 1e9 + 7;
        vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
        for (int i = 1; i <= n; i++) {
            dp[1][i] = 6;
        }
        for (int len = 2; len <= n; len++) {
            for (int last = 1; last <= n; last++) {
                for (int prev = 1; prev <= n; prev++) {
                    if (gcd(last, prev) == 1) {
                        dp[len][last] = (dp[len][last] + dp[len - 1][prev]) % mod;
                    }
                }
            }
        }
        int res = 0;
        for (int i = 1; i <= n; i++) {
            res = (res + dp[n][i]) % mod;
        }
        return res;
    }
    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
};
```
